import React, { useState } from "react";
import PrivateChat from "./PrivateChat";
import CallWindow from "./CallWindow";

export default function FriendsList({ friends, currentUser }) {
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [callFriend, setCallFriend] = useState(null);

  return (
    <div>
      <h3>Friends</h3>
      {friends.map(friend => (
        <div key={friend.userId}>
          {friend.userId}
          <button onClick={() => setSelectedFriend(friend)}>Chat</button>
          <button onClick={() => setCallFriend(friend)}>Call</button>
        </div>
      ))}
      {selectedFriend && <PrivateChat currentUser={currentUser} friend={selectedFriend} />}
      {callFriend && <CallWindow currentUser={currentUser} friend={callFriend} />}
    </div>
  );
}
